/*
 * precision_scale.ino — Automated Precision Scale (0–5 kg)
 *
 * Elements:
 *   1. HX711 + TAL220B Load Cell    — DOUT D3, CLK D4; 80 SPS, gain 128
 *   2. SSD1306 OLED (I²C 0x3C)     — live weight, MAX, unit
 *   3. Rotary Encoder KY-040        — tare (short) / unit toggle (long)
 *   4. Arduino Nano 3.0             — 8-sample avg, EEPROM tare, auto-sleep
 */

#include <Wire.h>
#include <HX711.h>
#include <Adafruit_SSD1306.h>
#include <EEPROM.h>
#include <avr/sleep.h>

// --- Pins ---
#define HX_DOUT  3
#define HX_CLK   4
#define ENC_CLK  2
#define ENC_DT   6
#define ENC_SW   5

// --- EEPROM ---
#define EE_TARE    0   // float (4 bytes)
#define EE_SCALE   4   // float (4 bytes)

// --- Constants ---
#define SAMPLES     8
#define IDLE_MS    (5UL * 60 * 1000)
#define G_TO_OZ    0.035274f

// --- Objects ---
HX711           hx;
Adafruit_SSD1306 oled(128, 64, &Wire, -1);

// --- State ---
bool   unit_oz    = false;
float  max_weight = 0.0f;
unsigned long last_activity = 0;

volatile bool enc_press  = false;
volatile bool enc_long   = false;
unsigned long press_ts   = 0;
void ICACHE_RAM_ATTR isr_sw() {
  if (!digitalRead(ENC_SW)) press_ts = millis();
  else {
    if (millis() - press_ts > 1000) enc_long  = true;
    else                            enc_press = true;
  }
}

void draw_oled(float weight_g, bool tare_flash) {
  float display = unit_oz ? weight_g * G_TO_OZ : weight_g;
  const char* unit = unit_oz ? "oz" : "g";
  char main_buf[16], max_buf[24];
  dtostrf(display, 7, unit_oz ? 2 : 1, main_buf);
  snprintf(max_buf, sizeof(max_buf), "MAX:%s %s", unit_oz ? "--" : "--", unit);
  float max_d = unit_oz ? max_weight * G_TO_OZ : max_weight;
  snprintf(max_buf, sizeof(max_buf), "MAX:%.1f %s", max_d, unit);

  oled.clearDisplay();
  oled.setTextColor(SSD1306_WHITE);
  oled.setTextSize(3);
  oled.setCursor(0, 4);
  oled.print(main_buf);
  oled.setTextSize(1);
  oled.setCursor(0, 48);
  oled.print(unit);
  oled.setCursor(40, 48);
  oled.print(max_buf);
  if (tare_flash) {
    oled.fillRect(90, 48, 38, 10, SSD1306_WHITE);
    oled.setTextColor(SSD1306_BLACK);
    oled.setCursor(92, 50);
    oled.print("TARE");
    oled.setTextColor(SSD1306_WHITE);
  }
  oled.display();
}

void calibrate_scale() {
  Serial.println(F("Remove all weight, press enter..."));
  while (!Serial.available()) delay(10); Serial.read();
  hx.tare();
  Serial.println(F("Place 500g, press enter..."));
  while (!Serial.available()) delay(10); Serial.read();
  long raw = hx.get_value(20);
  float sf = (float)raw / 500.0f;
  EEPROM.put(EE_SCALE, sf);
  hx.set_scale(sf);
  Serial.printf("Scale factor: %.2f\n", sf);
}

void setup() {
  Serial.begin(115200);
  Wire.begin();

  hx.begin(HX_DOUT, HX_CLK);
  float sf;
  EEPROM.get(EE_SCALE, sf);
  if (isnan(sf) || sf <= 0) sf = 2280.0f;  // default estimate
  hx.set_scale(sf);

  float tare;
  EEPROM.get(EE_TARE, tare);
  if (!isnan(tare)) hx.set_offset((long)tare);
  else hx.tare();

  oled.begin(SSD1306_SWITCHCAPVCC, 0x3C);
  oled.clearDisplay(); oled.display();

  pinMode(ENC_CLK, INPUT_PULLUP); pinMode(ENC_DT, INPUT_PULLUP); pinMode(ENC_SW, INPUT_PULLUP);
  attachInterrupt(digitalPinToInterrupt(ENC_SW), isr_sw, CHANGE);

  last_activity = millis();
  Serial.println(F("Scale ready (? for calibrate)."));
}

void loop() {
  static unsigned long last_disp = 0;
  static bool tare_flash = false;
  static unsigned long tare_flash_ts = 0;

  unsigned long now = millis();

  // --- Buttons ---
  noInterrupts();
  bool p = enc_press; enc_press = false;
  bool lp = enc_long; enc_long = false;
  interrupts();

  if (p) {
    // TARE
    hx.tare();
    EEPROM.put(EE_TARE, (float)hx.get_offset());
    max_weight = 0;
    tare_flash = true; tare_flash_ts = now;
    last_activity = now;
  }
  if (lp) { unit_oz = !unit_oz; last_activity = now; }
  if (tare_flash && now - tare_flash_ts > 500) tare_flash = false;

  // --- Auto-sleep ---
  if (now - last_activity > IDLE_MS) {
    oled.ssd1306_command(SSD1306_DISPLAYOFF);
    set_sleep_mode(SLEEP_MODE_PWR_DOWN);
    sleep_enable(); sleep_cpu(); sleep_disable();
    oled.ssd1306_command(SSD1306_DISPLAYON);
    last_activity = millis();
  }

  // --- Read + display at 5 Hz ---
  if (now - last_disp >= 200UL) {
    last_disp = now;
    float w = hx.get_units(SAMPLES);
    if (w < 0) w = 0;
    if (w > max_weight) { max_weight = w; last_activity = now; }
    draw_oled(w, tare_flash);
    Serial.printf("%.1f g\n", w);
  }

  // Serial calibrate trigger
  if (Serial.available() && Serial.read() == '?') calibrate_scale();
}
